"""Artifact storage — serves reports generated by agents.

Reports are read from the local REPORTS_DIR, and — if OBSIDIAN_VAULT_PATH
is set — merged with `{vault}/reports/` so the dashboard Files tab shows
artifacts from both the Mac Mini and the PC via Obsidian Sync.
"""

import os
from dataclasses import dataclass
from datetime import datetime
from pathlib import Path


@dataclass
class ArtifactInfo:
    date: str
    name: str
    size_bytes: int
    modified: str
    path: str


def _reports_roots() -> list[Path]:
    """Return all report directories to scan (local + Obsidian vault if set)."""
    roots: list[Path] = [Path(os.getenv("REPORTS_DIR", "./reports")).resolve()]
    vault = os.getenv("OBSIDIAN_VAULT_PATH", "").strip()
    if vault:
        vault_reports = Path(vault).expanduser() / "reports"
        if vault_reports.exists():
            resolved = vault_reports.resolve()
            if resolved not in roots:
                roots.append(resolved)
    return roots


def list_artifacts() -> list[ArtifactInfo]:
    """List all artifacts across all date directories and all roots.

    If the same (date, name) exists in multiple roots, the most recently
    modified copy wins (so edits on either machine show through).
    """
    merged: dict[tuple[str, str], ArtifactInfo] = {}
    for root in _reports_roots():
        if not root.exists():
            continue
        for day_dir in sorted(root.iterdir(), reverse=True):
            if not day_dir.is_dir():
                continue
            for file in sorted(day_dir.iterdir()):
                if not file.is_file():
                    continue
                stat = file.stat()
                info = ArtifactInfo(
                    date=day_dir.name,
                    name=file.name,
                    size_bytes=stat.st_size,
                    modified=datetime.fromtimestamp(stat.st_mtime).isoformat(),
                    path=f"{day_dir.name}/{file.name}",
                )
                key = (info.date, info.name)
                existing = merged.get(key)
                if existing is None or info.modified > existing.modified:
                    merged[key] = info

    # Return newest date first, then filename
    return sorted(merged.values(), key=lambda a: (a.date, a.name), reverse=True)


def get_artifact_path(date: str, name: str) -> Path:
    """Get a safe path to an artifact. Raises ValueError on traversal attempts.

    Searches all configured roots (local + vault). Returns the first match
    whose resolved path stays inside its root.
    """
    # Reject anything with path separators or traversal characters
    if "/" in date or "\\" in date or ".." in date:
        raise ValueError("invalid path: date")
    if "/" in name or "\\" in name or ".." in name:
        raise ValueError("invalid path: name")

    last_candidate: Path | None = None
    for root in _reports_roots():
        target = (root / date / name).resolve()
        try:
            target.relative_to(root)
        except ValueError:
            raise ValueError("invalid path: escapes root")
        last_candidate = target
        if target.exists():
            return target

    # Preserve prior behaviour: return a path (even if missing) so callers
    # can decide how to handle 404s. Fall back to the local root.
    if last_candidate is not None:
        return last_candidate
    raise ValueError("invalid path: no roots configured")
